import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { detectClaudeInstallScopes } from "./installScope.js";
let home;
beforeEach(() => {
    home = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-installscope-"));
});
afterEach(() => {
    fs.rmSync(home, { recursive: true, force: true });
});
function writeInstalledPlugins(payload) {
    const dir = path.join(home, ".claude", "plugins");
    fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(path.join(dir, "installed_plugins.json"), JSON.stringify(payload));
}
describe("detectClaudeInstallScopes", () => {
    it("returns the scope when the plugin is installed at user scope", () => {
        writeInstalledPlugins({
            version: 2,
            plugins: {
                "bitfab@bitfab": [{ scope: "user", version: "0.1.56" }],
            },
        });
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual(["user"]);
    });
    it("returns the project scope when only installed at project scope", () => {
        writeInstalledPlugins({
            version: 2,
            plugins: {
                "bitfab@bitfab": [
                    {
                        scope: "project",
                        projectPath: "/tmp/some/project",
                        version: "0.1.53",
                    },
                ],
            },
        });
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual([
            "project",
        ]);
    });
    it("returns both scopes when installed at user and project", () => {
        writeInstalledPlugins({
            version: 2,
            plugins: {
                "bitfab@bitfab": [
                    { scope: "user", version: "0.1.56" },
                    {
                        scope: "project",
                        projectPath: "/tmp/some/project",
                        version: "0.1.53",
                    },
                ],
            },
        });
        const scopes = detectClaudeInstallScopes("bitfab@bitfab", home);
        expect(scopes.sort()).toEqual(["project", "user"]);
    });
    it("deduplicates repeated scopes (e.g. multiple project installs)", () => {
        writeInstalledPlugins({
            version: 2,
            plugins: {
                "bitfab@bitfab": [
                    { scope: "project", projectPath: "/a" },
                    { scope: "project", projectPath: "/b" },
                ],
            },
        });
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual([
            "project",
        ]);
    });
    it("returns an empty array when the plugin key is absent", () => {
        writeInstalledPlugins({
            version: 2,
            plugins: {
                "other@marketplace": [{ scope: "user" }],
            },
        });
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual([]);
    });
    it("returns an empty array when the file does not exist", () => {
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual([]);
    });
    it("returns an empty array when the file is malformed", () => {
        const dir = path.join(home, ".claude", "plugins");
        fs.mkdirSync(dir, { recursive: true });
        fs.writeFileSync(path.join(dir, "installed_plugins.json"), "not-json{");
        expect(detectClaudeInstallScopes("bitfab@bitfab", home)).toEqual([]);
    });
});
